# Claims transformation: map department to a custom SAML attribute
# First, create a ClaimsMappingPolicy
$policyDef = @{
    ClaimsMappingPolicy = @{
        Version = 1
        IncludeBasicClaimSet = 'true'
        ClaimsSchema = @(
            @{
                Source = 'user'
                ID = 'department'
                SamlClaimType = 'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/department'
            },
            @{
                Source = 'user'
                ID = 'employeeid'
                SamlClaimType = 'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/employeeid'
            }
        )
    }
} | ConvertTo-Json -Depth 10

$policy = New-MgPolicyClaimMappingPolicy -DisplayName 'HR Portal Claims' `
    -Definition @($policyDef) -IsOrganizationDefault $false

# Assign the policy to the service principal
$ref = @{ '@odata.id' = "https://graph.microsoft.com/v1.0/policies/claimsMappingPolicies/$($policy.Id)" }
Invoke-MgGraphRequest -Method POST `
    -Uri "https://graph.microsoft.com/v1.0/servicePrincipals/$spId/claimsMappingPolicies/`$ref" `
    -Body ($ref | ConvertTo-Json)

# Create a Conditional Access policy targeting a specific enterprise app
Connect-MgGraph -Scopes 'Policy.ReadWrite.ConditionalAccess', 'Application.Read.All'

# Get the service principal ID for the app
$appSpId = (Get-MgServicePrincipal -Filter "displayName eq 'HR Portal'").Id

$caPolicy = @{
    displayName = 'Require MFA for HR Portal'
    state       = 'enabled'
    conditions  = @{
        users = @{
            includeUsers = @('All')
            excludeGroups = @('<break-glass-group-id>')
        }
        applications = @{
            includeApplications = @('<app-client-id>')  # client ID, not object ID
        }
        locations = @{ includeLocations = @('All') }
    }
    grantControls = @{
        operator        = 'AND'
        builtInControls = @('mfa', 'compliantDevice')
    }
}
New-MgIdentityConditionalAccessPolicy -BodyParameter $caPolicy

# List all CA policies that reference this app
Get-MgIdentityConditionalAccessPolicy -All |
    Where-Object {
        $_.Conditions.Applications.IncludeApplications -contains '<app-client-id>' -or
        $_.Conditions.Applications.IncludeApplications -contains 'All'
    } |
    Select-Object DisplayName, State,
        @{N='Grant';E={$_.GrantControls.BuiltInControls -join ', '}}

# Register an on-premises application through App Proxy
# Prerequisite: Application Proxy connector installed on on-prem server

# Step 1: Find available connector groups
Get-MgOnPremisePublishingProfileConnectorGroup -OnPremisesPublishingProfileId 'applicationProxy' |
    Select-Object Id, Name,
        @{N='ConnectorCount';E={(Get-MgOnPremisePublishingProfileConnectorGroupMember `
            -OnPremisesPublishingProfileId applicationProxy `
            -ConnectorGroupId $_.Id).Count}}

# Step 2: Create the App Proxy application
$connectorGroupId = '<connector-group-id>'
$proxyApp = @{
    displayName = 'Intranet HR Portal'
    onPremisesPublishing = @{
        externalUrl             = 'https://hrportal-contoso.msappproxy.net/'  # auto-generated
        internalUrl             = 'http://hrserver.corp.contoso.com/hrapp/'
        externalAuthenticationType = 'aadPreAuthentication'  # or passthru
        isHttpOnlyCookieEnabled    = $true
        isSecureCookieEnabled      = $true
        isPersistentCookieEnabled  = $false
        connectorGroupId        = $connectorGroupId
    }
}
$newApp = New-MgApplication @proxyApp

# Step 3: Create the service principal for the app
$sp = New-MgServicePrincipal -AppId $newApp.AppId -Tags @('WindowsAzureActiveDirectoryOnPremApp')

# Step 4: Configure Kerberos Constrained Delegation for Windows-integrated auth
Update-MgApplication -ApplicationId $newApp.Id -OnPremisesPublishing @{
    singleSignOnSettings = @{
        singleSignOnMode             = 'onPremisesKerberos'
        kerberosSignOnSettings = @{
            kerberosServicePrincipalName = 'HTTP/hrserver.corp.contoso.com'
            kerberosSignOnMappingAttributeType = 'userPrincipalName'
        }
    }
}
